function initAutocomplete(e,n,u,t,o,a,c=""){$(e).autocomplete({source:function(c,l){$.ajax({url:"index.php?route="+n+"&user_token="+u+"&"+t+"="+encodeURIComponent(c),dataType:"json",success:function(n){if(e.includes("category")||e.includes("manufacturer")){let u={};u[a]=" --- None --- ",u[o]="",n.unshift(u)}l($.map(n,function(e){return{label:e[a],value:e[o]}}))}})},select:function(n){$(e).val(decodeHTMLEntities(n.label)),c&&$(c).val(n.value)}})}